import re
from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Connect to Redis
redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

# Allowlist of safe Redis commands for cache management
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'SCAN', 'TYPE', 'MGET', 'MSET',
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS', 'HEXISTS',
    'LRANGE', 'LLEN', 'LINDEX',
    'SMEMBERS', 'SISMEMBER', 'SCARD',
    'ZRANGE', 'ZRANGEBYSCORE', 'ZCARD', 'ZSCORE',
    'DBSIZE', 'INFO', 'PING',
    'APPEND', 'INCR', 'DECR', 'INCRBY', 'DECRBY',
    'SETEX', 'PSETEX', 'SETNX',
    'PERSIST', 'RENAME',
}

# Dangerous commands that must never be executed
BLOCKED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'SHUTDOWN', 'DEBUG', 'CONFIG',
    'SLAVEOF', 'REPLICAOF', 'MODULE', 'ACL', 'BGSAVE',
    'BGREWRITEAOF', 'SAVE', 'SWAPDB', 'CLUSTER', 'MIGRATE',
    'RESTORE', 'DUMP', 'OBJECT', 'CLIENT', 'MONITOR',
    'EVAL', 'EVALSHA', 'SCRIPT', 'SUBSCRIBE', 'PSUBSCRIBE',
    'PUBLISH', 'MULTI', 'EXEC', 'DISCARD', 'WATCH', 'UNWATCH',
    'WAIT', 'COMMAND', 'LATENCY', 'MEMORY', 'SLOWLOG',
    'RESET', 'FAILOVER', 'PSYNC', 'REPLCONF', 'SELECT',
}

# Pattern to validate key names - prevent injection via key names
KEY_PATTERN = re.compile(r'^[a-zA-Z0-9_:\-\.\*\[\]]+$')

# Maximum number of arguments allowed
MAX_ARGS = 10

# Maximum length of any single argument
MAX_ARG_LENGTH = 1024


def validate_command(command_str):
    """Parse and validate the Redis command string."""
    if not command_str or not isinstance(command_str, str):
        return None, "Command must be a non-empty string"

    # Strip and normalize whitespace
    command_str = command_str.strip()

    if not command_str:
        return None, "Command must be a non-empty string"

    # Split command into parts (simple split; does not handle quoted strings with spaces)
    # For more complex parsing, use shlex
    try:
        import shlex
        parts = shlex.split(command_str)
    except ValueError as e:
        return None, f"Invalid command format: {str(e)}"

    if not parts:
        return None, "Command must be a non-empty string"

    # Extract the command name
    cmd_name = parts[0].upper()

    # Check against blocked commands first
    if cmd_name in BLOCKED_COMMANDS:
        return None, f"Command '{cmd_name}' is blocked for security reasons"

    # Check against allowlist
    if cmd_name not in ALLOWED_COMMANDS:
        return None, f"Command '{cmd_name}' is not allowed. Allowed commands: {sorted(ALLOWED_COMMANDS)}"

    # Validate argument count
    args = parts[1:]
    if len(args) > MAX_ARGS:
        return None, f"Too many arguments (max {MAX_ARGS})"

    # Validate each argument length
    for i, arg in enumerate(args):
        if len(arg) > MAX_ARG_LENGTH:
            return None, f"Argument {i+1} exceeds maximum length of {MAX_ARG_LENGTH}"

    # For commands that take key names, validate key patterns
    # to prevent potential injection through crafted key names
    key_commands_with_key_at_pos = {
        'GET': [0], 'SET': [0], 'DEL': list(range(MAX_ARGS)),
        'EXISTS': [0], 'EXPIRE': [0], 'TTL': [0], 'PTTL': [0],
        'TYPE': [0], 'MGET': list(range(MAX_ARGS)),
        'HGET': [0], 'HSET': [0], 'HDEL': [0], 'HGETALL': [0],
        'HKEYS': [0], 'HVALS': [0], 'HEXISTS': [0],
        'LRANGE': [0], 'LLEN': [0], 'LINDEX': [0],
        'SMEMBERS': [0], 'SISMEMBER': [0], 'SCARD': [0],
        'ZRANGE': [0], 'ZRANGEBYSCORE': [0], 'ZCARD': [0], 'ZSCORE': [0],
        'APPEND': [0], 'INCR': [0], 'DECR': [0], 'INCRBY': [0], 'DECRBY': [0],
        'SETEX': [0], 'PSETEX': [0], 'SETNX': [0],
        'PERSIST': [0], 'RENAME': [0, 1],
        'KEYS': [0], 'SCAN': [],
        'MSET': list(range(0, MAX_ARGS, 2)),  # Even positions are keys
    }

    if cmd_name in key_commands_with_key_at_pos:
        key_positions = key_commands_with_key_at_pos[cmd_name]
        for pos in key_positions:
            if pos < len(args):
                if not KEY_PATTERN.match(args[pos]):
                    return None, (
                        f"Invalid key name at position {pos+1}: '{args[pos]}'. "
                        f"Keys must match pattern: {KEY_PATTERN.pattern}"
                    )

    # For KEYS command, restrict glob patterns to prevent expensive scans
    if cmd_name == 'KEYS' and args:
        pattern = args[0]
        # Only allow patterns with a reasonable prefix before any wildcard
        if pattern == '*':
            return None, "KEYS * is not allowed. Please provide a more specific pattern (e.g., 'prefix:*')"
        # Ensure pattern has at least 3 non-wildcard characters
        prefix = pattern.split('*')[0].replace('?', '').replace('[', '').replace(']', '')
        if len(prefix) < 3:
            return None, "KEYS pattern must have at least 3 non-wildcard prefix characters"

    return (cmd_name, args), None


def sanitize_response(response):
    """Sanitize Redis response for safe JSON serialization."""
    if response is None:
        return None
    if isinstance(response, bytes):
        return response.decode('utf-8', errors='replace')
    if isinstance(response, (int, float, str, bool)):
        return response
    if isinstance(response, list):
        return [sanitize_response(item) for item in response]
    if isinstance(response, dict):
        return {
            sanitize_response(k): sanitize_response(v)
            for k, v in response.items()
        }
    if isinstance(response, set):
        return [sanitize_response(item) for item in response]
    return str(response)


@app.route('/api/admin/redis', methods=['GET', 'POST'])
def execute_redis_command():
    """Execute a validated Redis command."""
    # Get command from request
    if request.method == 'POST':
        data = request.get_json(silent=True) or {}
        command_str = data.get('command', '') or request.args.get('command', '')
    else:
        command_str = request.args.get('command', '')

    if not command_str:
        return jsonify({
            'success': False,
            'error': 'Missing required parameter: command',
            'allowed_commands': sorted(ALLOWED_COMMANDS)
        }), 400

    # Validate the command
    parsed, error = validate_command(command_str)
    if error:
        return jsonify({
            'success': False,
            'error': error
        }), 403

    cmd_name, args = parsed

    try:
        # Execute the validated command
        result = redis_client.execute_command(cmd_name, *args)
        sanitized_result = sanitize_response(result)

        return jsonify({
            'success': True,
            'command': cmd_name,
            'args': args,
            'result': sanitized_result
        }), 200

    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}',
            'command': cmd_name
        }), 500
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500


@app.route('/api/admin/redis/commands', methods=['GET'])
def list_allowed_commands():
    """List all allowed Redis commands."""
    return jsonify({
        'allowed_commands': sorted(ALLOWED_COMMANDS),
        'max_args': MAX_ARGS,
        'max_arg_length': MAX_ARG_LENGTH,
        'key_pattern': KEY_PATTERN.pattern
    }), 200


@app.route('/api/admin/redis/health', methods=['GET'])
def redis_health():
    """Check Redis connection health."""
    try:
        result = redis_client.ping()
        return jsonify({
            'success': True,
            'redis_connected': result
        }), 200
    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'redis_connected': False,
            'error': str(e)
        }), 503


